UPDATE coaching.exercise SET
  name = 'Random Gate Acceleration',
  description = 'The athlete waits for a live cue (coach names or points to gate), selects the correct answer, performs the movement response, and resets before the next rep. The rep counts only when the athlete reacts to the real stimulus rather than guessing early.',
  card_summary = 'Random Gate Acceleration is a reaction-time-reduction drill for gate-choice acceleration without pre-planned direction. Use it when the goal is faster stimulus recognition, cleaner first movement, and safer reset behavior without turning reaction work into conditioning.',
  coach_language = 'Primary subrole: reactive_agility_output. Coach Random Gate Acceleration as a quality-first reaction drill: define the cue, remove ambiguous starts, require a clean answer, and rest long enough that speed, accuracy, posture, and safety stay intact.',
