UPDATE coaching.exercise SET
  name = 'Partner Shadow Defense Drill',
  description = 'The athlete waits for a live cue (leader movement in a box), selects the correct answer, performs the movement response, and resets before the next rep. The rep counts only when the athlete reacts to the real stimulus rather than guessing early.',
  card_summary = 'Partner Shadow Defense Drill is a reaction-time-reduction drill for opponent body-language reading without collision or fatigue. Use it when the goal is faster stimulus recognition, cleaner first movement, and safer reset behavior without turning reaction work into conditioning.',
  coach_language = 'Primary subrole: perception_action_reactive_movement. Coach Partner Shadow Defense Drill as a quality-first reaction drill: define the cue, remove ambiguous starts, require a clean answer, and rest long enough that speed, accuracy, posture, and safety stay intact.',
  athlete_language = 'See the cue, answer fast, finish clean, then reset. Do not guess before the signal.',
