  primary_order_slot = 'partner_shadow_defense_drill',
  default_sets = 2,
  default_reps = 6,
  default_work_seconds = 15,
  default_rest_seconds = 30,
  est_seconds_per_set = 45,
  movement_requirements = '{"stimulus":"leader movement in a box","decision_pattern":"shadow spacing and angles safely","space_needed":"Clear lane, small grid, or box with safe stopping room and no crossing traffic.","setup":"Mark start, finish/reset area, and any target lanes. Explain valid cues and decoy cues before the first rep. Rehearse once at low speed, then randomize the cue.","primary_joint_actions":["hip_flexion_extension","ankle_stiffness","trunk_bracing"],"primary_tissues":["calves","quadriceps","glutes","adductors","core"],"primary_motor_control_demands":["stimulus_discrimination","response_inhibition","first_step_timing","postural_reset"],"postural_shape":null,"breathing_demand":"brief brace with relaxed reset breathing","balance_demand":"dynamic balance during reaction and reset","coordination_demand":"high cue-to-action coordination","impact_level":1,"quality_gate":"Rep counts only when the athlete waits for the valid cue, chooses correctly, moves with control, brakes or catches safely, and resets posture before the next cue.","stop_signs":["false starts or guessing increase","wrong-direction responses repeat","posture, landing, catch, or braking quality drops","spacing becomes unsafe","pain, dizziness, panic, or symptom increase appears"],"reaction_time_reduction_target":{"stimulus":"leader movement in a box","decisionPattern":"shadow spacing and angles safely","primaryLatencyTarget":"shorten the time from valid cue recognition to first organized movement","secondaryTargets":["reduce false starts and guessing","improve first-step direction accuracy","improve braking or catch timing after the response","preserve posture and spacing while reacting"],"measurementIdeas":["track correct responses out of total cues","track false starts or wrong-direction responses","use video or timer when precise latency measurement is needed","progress only when accuracy stays high at the current speed"]}}'::jsonb,
  coaching_execution = '{"movement_description":"Partner Shadow Defense Drill: the athlete responds to leader movement in a box with the required answer: shadow spacing and angles safely.","setup":["Create a clear start position and target area.","Define the valid cue and any decoy cues.","Use enough spacing that a wrong response does not create collision risk.","Give one low-speed rehearsal before randomized reps."],"execution_steps":["Athlete sets posture and waits without pre-loading into the answer.","Coach or partner gives the cue at an unpredictable time.","Athlete reacts only to the valid cue and completes the movement response.","Athlete brakes, catches, or finishes safely.","Athlete resets breathing, stance, and attention before the next cue."],"breathing_cues":["Breathe quietly before the cue.","Exhale during the reset, not during the wait as a false trigger.","Avoid breath-holding across repeated cues."],"coach_cues":["Wait for information.","First step answers the cue.","Fast eyes, quiet body.","Brake before the next rep.","Reset so the next rep is real."],"athlete_cues":["Do not guess.","See it, then go.","Clean finish.","Reset your eyes and feet."],"quality_gate":["At least 80-90% correct responses at the chosen speed before progression.","No unsafe collisions, stumbles, or uncontrolled finishes.","Response quality stays crisp across the set."],"common_faults":["jumping early before the cue","turning the drill into a race or conditioning station","adding too many cue choices too soon","late braking or unsafe spacing","looking at the coach instead of the relevant target when scanning is required"],"stop_signs":["false starts or wrong choices stack up","athlete cannot explain the cue rule","mechanics degrade from fatigue","pain or symptoms appear"]}'::jsonb,
