  description = 'The athlete waits for a live cue (partner enters lane or coach blocks lane), selects the correct answer, performs the movement response, and resets before the next rep. The rep counts only when the athlete reacts to the real stimulus rather than guessing early.',
  card_summary = 'Collision-Avoidance Lane Change is a reaction-time-reduction drill for reaction to moving obstacles while maintaining safe lanes. Use it when the goal is faster stimulus recognition, cleaner first movement, and safer reset behavior without turning reaction work into conditioning.',
  coach_language = 'Primary subrole: perception_action_reactive_movement. Coach Collision-Avoidance Lane Change as a quality-first reaction drill: define the cue, remove ambiguous starts, require a clean answer, and rest long enough that speed, accuracy, posture, and safety stay intact.',
  athlete_language = 'See the cue, answer fast, finish clean, then reset. Do not guess before the signal.',
  movement_family = 'Spatial Awareness, Multi-Cue, and Game Constraint Reaction',
  primary_phase_key = 'movement_intelligence',
  phase_subrole = 'perception_action_reactive_movement',
  primary_order_slot = 'collision_avoidance_lane_change',
  default_sets = 2,
  default_reps = 6,
  default_work_seconds = 15,
  default_rest_seconds = 30,
  est_seconds_per_set = 45,
  movement_requirements = '{"stimulus":"partner enters lane or coach blocks lane","decision_pattern":"change lane safely without panic","space_needed":"Clear lane, small grid, or box with safe stopping room and no crossing traffic.","setup":"Mark start, finish/reset area, and any target lanes. Explain valid cues and decoy cues before the first rep. Rehearse once at low speed, then randomize the cue.","primary_joint_actions":["hip_flexion_extension","ankle_stiffness","trunk_bracing"],"primary_tissues":["calves","quadriceps","glutes","adductors","core"],"primary_motor_control_demands":["stimulus_discrimination","response_inhibition","first_step_timing","postural_reset"],"postural_shape":null,"breathing_demand":"brief brace with relaxed reset breathing","balance_demand":"dynamic balance during reaction and reset","coordination_demand":"high cue-to-action coordination","impact_level":3,"quality_gate":"Rep counts only when the athlete waits for the valid cue, chooses correctly, moves with control, brakes or catches safely, and resets posture before the next cue.","stop_signs":["false starts or guessing increase","wrong-direction responses repeat","posture, landing, catch, or braking quality drops","spacing becomes unsafe","pain, dizziness, panic, or symptom increase appears"],"reaction_time_reduction_target":{"stimulus":"partner enters lane or coach blocks lane","decisionPattern":"change lane safely without panic","primaryLatencyTarget":"shorten the time from valid cue recognition to first organized movement","secondaryTargets":["reduce false starts and guessing","improve first-step direction accuracy","improve braking or catch timing after the response","preserve posture and spacing while reacting"],"measurementIdeas":["track correct responses out of total cues","track false starts or wrong-direction responses","use video or timer when precise latency measurement is needed","progress only when accuracy stays high at the current speed"]}}'::jsonb,
  coaching_execution = '{"movement_description":"Collision-Avoidance Lane Change: the athlete responds to partner enters lane or coach blocks lane with the required answer: change lane safely without panic.","setup":["Create a clear start position and target area.","Define the valid cue and any decoy cues.","Use enough spacing that a wrong response does not create collision risk.","Give one low-speed rehearsal before randomized reps."],"execution_steps":["Athlete sets posture and waits without pre-loading into the answer.","Coach or partner gives the cue at an unpredictable time.","Athlete reacts only to the valid cue and completes the movement response.","Athlete brakes, catches, or finishes safely.","Athlete resets breathing, stance, and attention before the next cue."],"breathing_cues":["Breathe quietly before the cue.","Exhale during the reset, not during the wait as a false trigger.","Avoid breath-holding across repeated cues."],"coach_cues":["Wait for information.","First step answers the cue.","Fast eyes, quiet body.","Brake before the next rep.","Reset so the next rep is real."],"athlete_cues":["Do not guess.","See it, then go.","Clean finish.","Reset your eyes and feet."],"quality_gate":["At least 80-90% correct responses at the chosen speed before progression.","No unsafe collisions, stumbles, or uncontrolled finishes.","Response quality stays crisp across the set."],"common_faults":["jumping early before the cue","turning the drill into a race or conditioning station","adding too many cue choices too soon","late braking or unsafe spacing","looking at the coach instead of the relevant target when scanning is required"],"stop_signs":["false starts or wrong choices stack up","athlete cannot explain the cue rule","mechanics degrade from fatigue","pain or symptoms appear"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["acceleration work","sport skill block","agility block","strength or conditioning later in session"],"pairs_well_after":["general warm-up","dynamic mobility","basic landing or braking prep","low-speed cue rehearsal"],"good_for_sessions":["reaction_time_reduction","neural_readiness","perception_action_skill","field_court_sport_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["athlete has pain or acute injury with the required movement","space or supervision is insufficient for reaction work","fatigue is already causing guessing, poor braking, or unsafe landings","the coach intends to use the drill as punishment or conditioning"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Vortex exercise_card_details_for_llm.md - Card v2 authoring guide","Internal Vortex demo recommended - show cue setup, athlete response, safe reset, and common false-start correction"],"internal_notes":["Film Collision-Avoidance Lane Change from a view that shows cue source, athlete start posture, first step, and finish/reset.","Use video review to identify false starts, delayed recognition, wrong first step, or unsafe braking.","Keep this as a reaction-time card, not conditioning."]}'::jsonb,
  updated_at = now()
WHERE slug = 'collision-avoidance-lane-change';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'collision_avoidance_lane_change',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = TRUE,
  fatigue_sensitivity = 5,
  fatigue_cost = 1,
  technical_complexity = 4,
  impact_level = 3,
  intensity_ceiling = 'moderate-low',
  notes = 'Use after the general warm-up while the nervous system is fresh and before fatigue-heavy strength, conditioning, or long competitive play. Keep cues crisp and stop before decision quality drops.'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'movement_intelligence'
JOIN coaching.phase_order_slot pos ON pos.key = 'collision_avoidance_lane_change' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'collision-avoidance-lane-change';

INSERT INTO coaching.exercise_phase_profile (
