UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'pregnancy_postpartum' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('split-stance-auditory-sprint-start', 'Use symptom-guided low-impact versions. Avoid breath-holding, collision, aggressive cutting, hard impact, or positions that create pressure, leaking, heaviness, dizziness, or pain.', 'No default gender-specific adjustment. Individualize by training age, injury history, confidence with reactive work, pelvic-floor or abdominal-pressure symptoms, joint laxity, fatigue state, and sport demand.'),
