-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Reaction-time reduction depends on perception, inhibition, first-step timing, safe braking, and reset behavior — not fatigue or guessing.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('split-stance-auditory-sprint-start', 'Auditory cue-to-first-step sprint latency with a stable start shape. Reaction-time work improves when the cue is specific, the answer is simple enough to repeat correctly, and the athlete gets enough recovery to process feedback. This drill links perception, posture, and action so the next response can become faster and cleaner rather than just more tired.', 'Belongs in Output because the response includes high-intent acceleration, cutting, braking, or explosive movement that requires freshness, low volume, and full recovery.', 'Place after Prepare & Access and any needed Movement Intelligence, before heavy strength, long sport blocks, or conditioning. Keep volume low, intent high, and rest long enough for every response to stay fast and accurate.', 'Do not turn this into conditioning, punishment, or a long chaos circuit. The most common error is adding speed, choices, partner pressure, or fatigue before the athlete can read the cue and answer safely. Stop the set when the athlete guesses, drifts, collides, lands loudly, loses posture, or cannot reset.', 'Scale one constraint at a time: cue choices, distance, speed, object speed, partner pressure, impact, field size, and rest. Progress only when the athlete reacts to the correct cue with accurate movement, safe braking or catch timing, and consistent reset behavior.'),
  ('partner-point-reactive-sprint-start', 'Visual cue-to-acceleration response using a partner point. Reaction-time work improves when the cue is specific, the answer is simple enough to repeat correctly, and the athlete gets enough recovery to process feedback. This drill links perception, posture, and action so the next response can become faster and cleaner rather than just more tired.', 'Belongs in Output because the response includes high-intent acceleration, cutting, braking, or explosive movement that requires freshness, low volume, and full recovery.', 'Place after Prepare & Access and any needed Movement Intelligence, before heavy strength, long sport blocks, or conditioning. Keep volume low, intent high, and rest long enough for every response to stay fast and accurate.', 'Do not turn this into conditioning, punishment, or a long chaos circuit. The most common error is adding speed, choices, partner pressure, or fatigue before the athlete can read the cue and answer safely. Stop the set when the athlete guesses, drifts, collides, lands loudly, loses posture, or cannot reset.', 'Scale one constraint at a time: cue choices, distance, speed, object speed, partner pressure, impact, field size, and rest. Progress only when the athlete reacts to the correct cue with accurate movement, safe braking or catch timing, and consistent reset behavior.'),
  ('tennis-ball-drop-acceleration-chase', 'Fast first-step reaction to a falling object with a clear success signal. Reaction-time work improves when the cue is specific, the answer is simple enough to repeat correctly, and the athlete gets enough recovery to process feedback. This drill links perception, posture, and action so the next response can become faster and cleaner rather than just more tired.', 'Belongs in Output because the response includes high-intent acceleration, cutting, braking, or explosive movement that requires freshness, low volume, and full recovery.', 'Place after Prepare & Access and any needed Movement Intelligence, before heavy strength, long sport blocks, or conditioning. Keep volume low, intent high, and rest long enough for every response to stay fast and accurate.', 'Do not turn this into conditioning, punishment, or a long chaos circuit. The most common error is adding speed, choices, partner pressure, or fatigue before the athlete can read the cue and answer safely. Stop the set when the athlete guesses, drifts, collides, lands loudly, loses posture, or cannot reset.', 'Scale one constraint at a time: cue choices, distance, speed, object speed, partner pressure, impact, field size, and rest. Progress only when the athlete reacts to the correct cue with accurate movement, safe braking or catch timing, and consistent reset behavior.'),
